+  let xPrime = 0;
+  let yPrime = 0;
+
+  if (e < 0.99 && a !== null) {
+    // --- Elliptic Orbit ---
+    let n = elements.n;
+    if (n === null) {
+      // Derive mean motion n (deg/day) from semi-major axis a (au)
